<style>
    .chat-fab{position:fixed;right:24px;bottom:24px;z-index:1040;width:58px;height:58px;border:0;border-radius:50%;display:grid;place-items:center;background:#2d6a4f;color:#fff;font-size:1.45rem;box-shadow:0 12px 30px rgba(45,106,79,.38);transition:transform .2s,background .2s}
    .chat-fab:hover{transform:translateY(-3px);background:#245840}.chat-fab-badge{position:absolute;right:-2px;top:-3px;min-width:21px;height:21px;padding:0 5px;border-radius:11px;display:none;place-items:center;background:#dc3545;color:#fff;font:700 .7rem/1 system-ui;border:2px solid #fff}
    .chat-overlay{position:fixed;inset:0;z-index:1060;display:flex;align-items:center;justify-content:center;padding:18px;background:rgba(15,23,42,.55);backdrop-filter:blur(3px);opacity:0;visibility:hidden;transition:.2s}
    .chat-overlay.active{opacity:1;visibility:visible}.chat-window{width:min(820px,100%);height:min(620px,calc(100vh - 36px));height:min(620px,calc(100dvh - 36px));min-height:0;display:grid;grid-template-columns:minmax(240px,285px) minmax(0,1fr);overflow:hidden;background:#fff;color:#17202a;border-radius:20px;box-shadow:0 24px 70px rgba(0,0,0,.28);transform:translateY(16px);transition:.2s}
    .chat-overlay.active .chat-window{transform:none}.chat-list-pane{display:flex;flex-direction:column;min-width:0;min-height:0;background:#f8faf9;border-right:1px solid #e5e7eb}.chat-pane-head{display:flex;align-items:center;justify-content:space-between;flex:0 0 auto;padding:19px 18px;border-bottom:1px solid #e5e7eb}.chat-pane-head h2{font-size:1.05rem;margin:0;font-weight:800}.chat-close{border:0;background:transparent;color:#64748b;font-size:1.3rem}.chat-search{flex:0 0 auto;min-width:0;margin:13px 14px;padding:10px 12px;border:1px solid #dbe3df;border-radius:10px;background:#fff;color:#17202a;outline:none}.chat-conversations{min-height:0;overflow:auto;overscroll-behavior:contain;flex:1}.chat-contact{width:100%;display:flex;gap:11px;align-items:center;padding:12px 14px;border:0;border-bottom:1px solid #edf1ef;background:transparent;text-align:left;color:inherit}.chat-contact:hover,.chat-contact.active{background:#e8f5ee}.chat-avatar{width:42px;height:42px;flex:0 0 42px;border-radius:50%;display:grid;place-items:center;background:#2d6a4f;color:#fff;font-weight:800}.chat-contact-copy{min-width:0;flex:1}.chat-contact-name{font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.chat-preview{font-size:.78rem;color:#64748b;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.chat-unread{min-width:20px;height:20px;padding:0 5px;border-radius:10px;display:grid;place-items:center;background:#2d6a4f;color:#fff;font-size:.68rem;font-weight:700}.chat-main-pane{display:flex;flex-direction:column;min-width:0;min-height:0;background:#fff}.chat-main-head{display:flex;align-items:center;gap:10px;min-height:68px;flex:0 0 auto;padding:13px 18px;border-bottom:1px solid #e5e7eb}.chat-main-head>div:last-child{min-width:0}.chat-main-name{overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.chat-back{display:none;border:0;background:transparent;font-size:1.15rem}.chat-main-name{font-weight:800}.chat-main-status{font-size:.75rem;color:#64748b}.chat-messages{min-height:0;flex:1;overflow:auto;overscroll-behavior:contain;padding:20px;display:flex;flex-direction:column;gap:10px;background:#f7faf8}.chat-empty{margin:auto;text-align:center;color:#64748b;max-width:280px}.chat-empty i{display:block;font-size:2.5rem;color:#8fb8a3;margin-bottom:8px}.chat-bubble{max-width:78%;padding:10px 13px;border-radius:15px;background:#fff;border:1px solid #e5e7eb;box-shadow:0 2px 5px rgba(15,23,42,.04);overflow-wrap:anywhere}.chat-bubble.mine{align-self:flex-end;background:#2d6a4f;color:#fff;border-color:#2d6a4f;border-bottom-right-radius:4px}.chat-bubble.theirs{align-self:flex-start;border-bottom-left-radius:4px}.chat-time{display:block;margin-top:4px;font-size:.65rem;opacity:.7;text-align:right}.chat-form{display:none;flex:0 0 auto;gap:9px;padding:13px 16px;border-top:1px solid #e5e7eb}.chat-form.active{display:flex}.chat-input{flex:1;min-width:0;padding:11px 14px;border:1px solid #dbe3df;border-radius:22px;outline:none}.chat-send{width:44px;height:44px;flex:0 0 44px;border:0;border-radius:50%;background:#2d6a4f;color:#fff}.chat-loading{padding:24px;text-align:center;color:#64748b}
    html.dark .chat-window,html.dark .chat-main-pane{background:#1e293b;color:#e2e8f0}html.dark .chat-list-pane,html.dark .chat-messages{background:#0f172a}html.dark .chat-pane-head,html.dark .chat-main-head,html.dark .chat-form,html.dark .chat-list-pane{border-color:#334155}html.dark .chat-search,html.dark .chat-input,html.dark .chat-bubble.theirs{background:#1e293b;color:#e2e8f0;border-color:#334155}html.dark .chat-contact{border-color:#253449}html.dark .chat-contact:hover,html.dark .chat-contact.active{background:#244535}
    @media(max-width:768px){.chat-overlay{padding:10px}.chat-window{grid-template-columns:minmax(220px,40%) minmax(0,1fr)}}
    @media(max-width:650px){.chat-fab{right:max(16px,env(safe-area-inset-right));bottom:max(16px,env(safe-area-inset-bottom))}.chat-overlay{padding:0}.chat-window{width:100%;height:100vh;height:100dvh;max-height:none;border-radius:0;grid-template-columns:minmax(0,1fr)}.chat-main-pane{display:none}.chat-window.show-thread .chat-list-pane{display:none}.chat-window.show-thread .chat-main-pane{display:flex}.chat-back{display:inline-grid;place-items:center;flex:0 0 36px;width:36px;height:36px}.chat-pane-head{padding:calc(14px + env(safe-area-inset-top)) 15px 14px}.chat-main-head{padding:calc(10px + env(safe-area-inset-top)) 12px 10px}.chat-messages{padding:14px 12px}.chat-bubble{max-width:88%}.chat-form{padding:10px max(10px,env(safe-area-inset-right)) calc(10px + env(safe-area-inset-bottom)) max(10px,env(safe-area-inset-left))}.chat-input{font-size:16px}}
    @media(max-width:380px){.chat-avatar{width:36px;height:36px;flex-basis:36px}.chat-contact{padding:10px 12px}.chat-messages{padding-inline:9px}.chat-bubble{max-width:92%}}
    @media(max-height:520px) and (min-width:651px){.chat-overlay{padding:8px}.chat-window{height:calc(100vh - 16px);height:calc(100dvh - 16px);border-radius:14px}.chat-pane-head{padding:12px 15px}.chat-main-head{min-height:56px;padding:8px 14px}.chat-messages{padding:12px}.chat-form{padding:8px 12px}}
</style>

<button type="button" class="chat-fab" id="chatFab" aria-label="Ouvrir les discussions" title="Discussions">
    <i class="bi bi-chat-dots-fill"></i><span class="chat-fab-badge" id="chatBadge">0</span>
</button>
<div class="chat-overlay" id="chatOverlay" aria-hidden="true">
    <section class="chat-window" id="chatWindow" role="dialog" aria-modal="true" aria-labelledby="chatTitle">
        <aside class="chat-list-pane">
            <header class="chat-pane-head"><h2 id="chatTitle"><i class="bi bi-chat-dots me-2"></i>Discussions</h2><button class="chat-close" type="button" aria-label="Fermer"><i class="bi bi-x-lg"></i></button></header>
            <input class="chat-search" id="chatSearch" type="search" placeholder="Rechercher…" aria-label="Rechercher une discussion">
            <div class="chat-conversations" id="chatConversations"><div class="chat-loading">Chargement…</div></div>
        </aside>
        <main class="chat-main-pane">
            <header class="chat-main-head"><button class="chat-back" type="button" aria-label="Retour"><i class="bi bi-arrow-left"></i></button><div class="chat-avatar" id="chatActiveAvatar"><i class="bi bi-person"></i></div><div><div class="chat-main-name" id="chatActiveName">Sélectionnez une discussion</div><div class="chat-main-status" id="chatActiveStatus">Messagerie privée</div></div></header>
            <div class="chat-messages" id="chatMessages"><div class="chat-empty"><i class="bi bi-chat-square-heart"></i>Choisissez une personne pour commencer la discussion.</div></div>
            <form class="chat-form" id="chatForm"><input class="chat-input" id="chatInput" maxlength="2000" autocomplete="off" placeholder="Écrivez votre message…" aria-label="Message"><button class="chat-send" type="submit" aria-label="Envoyer"><i class="bi bi-send-fill"></i></button></form>
        </main>
    </section>
</div>
<script>
(()=>{
    // Le partial est chargé depuis la sidebar : déplacer les éléments fixes sous
    // body évite qu'une transformation CSS mobile limite leur zone d'affichage.
    document.body.append(document.getElementById('chatFab'), document.getElementById('chatOverlay'));
    const api=<?= json_encode($chatApiPath ?? '../models/traitement/chat-post.php', JSON_UNESCAPED_SLASHES) ?>,overlay=document.getElementById('chatOverlay'),win=document.getElementById('chatWindow'),list=document.getElementById('chatConversations'),messages=document.getElementById('chatMessages'),form=document.getElementById('chatForm'),input=document.getElementById('chatInput'),badge=document.getElementById('chatBadge');
    let contacts=[],active=null,loaded=false;
    const esc=value=>{const el=document.createElement('div');el.textContent=value??'';return el.innerHTML};
    async function request(action,data={}){const response=await fetch(api,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action,...data})});const result=await response.json();if(!response.ok||!result.success)throw new Error(result.message||'Une erreur est survenue.');return result}
    function initials(person){return ((person.prenom?.[0]||'')+(person.nom?.[0]||'')).toUpperCase()||'?'}
    function renderList(query=''){const filtered=contacts.filter(c=>(c.prenom+' '+c.nom).toLowerCase().includes(query.toLowerCase()));list.innerHTML=filtered.length?filtered.map(c=>`<button type="button" class="chat-contact ${active?.user_id==c.user_id?'active':''}" data-user="${c.user_id}"><span class="chat-avatar">${esc(initials(c))}</span><span class="chat-contact-copy"><span class="chat-contact-name">${esc(c.prenom+' '+c.nom)}</span><span class="chat-preview">${esc(c.dernier_message||'Démarrer une discussion')}</span></span>${Number(c.non_lus)?`<span class="chat-unread">${c.non_lus}</span>`:''}</button>`).join(''):'<div class="chat-loading">Aucun contact trouvé.</div>';list.querySelectorAll('.chat-contact').forEach(button=>button.onclick=()=>openThread(Number(button.dataset.user)))}
    async function loadList(){try{const result=await request('list');contacts=result.contacts;const unread=contacts.reduce((n,c)=>n+Number(c.non_lus||0),0);badge.textContent=unread>99?'99+':unread;badge.style.display=unread?'grid':'none';renderList(document.getElementById('chatSearch').value);loaded=true}catch(error){list.innerHTML=`<div class="chat-loading">${esc(error.message)}</div>`}}
    async function openThread(userId){active=contacts.find(c=>Number(c.user_id)===userId);if(!active)return;document.getElementById('chatActiveName').textContent=active.prenom+' '+active.nom;document.getElementById('chatActiveAvatar').textContent=initials(active);document.getElementById('chatActiveStatus').textContent=active.role_label;form.classList.add('active');win.classList.add('show-thread');renderList(document.getElementById('chatSearch').value);messages.innerHTML='<div class="chat-loading">Chargement…</div>';try{const result=await request('messages',{contact_id:userId});active.chat_id=result.chat_id;messages.innerHTML=result.messages.length?result.messages.map(m=>`<div class="chat-bubble ${m.est_moi?'mine':'theirs'}">${esc(m.contenu)}<span class="chat-time">${esc(m.heure)}</span></div>`).join(''):'<div class="chat-empty"><i class="bi bi-chat-heart"></i>Envoyez le premier message.</div>';messages.scrollTop=messages.scrollHeight;active.non_lus=0;loadList();input.focus()}catch(error){messages.innerHTML=`<div class="chat-empty">${esc(error.message)}</div>`}}
    function close(){overlay.classList.remove('active');overlay.setAttribute('aria-hidden','true');document.body.style.overflow=''}
    document.getElementById('chatFab').onclick=()=>{overlay.classList.add('active');overlay.setAttribute('aria-hidden','false');document.body.style.overflow='hidden';if(!loaded)loadList()};
    overlay.querySelector('.chat-close').onclick=close;overlay.querySelector('.chat-back').onclick=()=>win.classList.remove('show-thread');document.getElementById('chatSearch').oninput=e=>renderList(e.target.value);
    form.onsubmit=async e=>{e.preventDefault();const contenu=input.value.trim();if(!contenu||!active)return;input.value='';input.disabled=true;try{await request('send',{contact_id:active.user_id,contenu});await openThread(Number(active.user_id))}catch(error){input.value=contenu;alert(error.message)}finally{input.disabled=false;input.focus()}};
    window.openProductChat=async product=>{overlay.classList.add('active');overlay.setAttribute('aria-hidden','false');document.body.style.overflow='hidden';messages.innerHTML='<div class="chat-loading">Ouverture de la discussion…</div>';try{const url=new URL(product.url,window.location.href).href;const contenu=`Bonjour, je souhaite discuter de votre produit « ${product.name} » : ${url}`;await request('send',{contact_id:Number(product.farmerId),contenu});await loadList();await openThread(Number(product.farmerId))}catch(error){messages.innerHTML=`<div class="chat-empty">${esc(error.message)}</div>`}};
    loadList();setInterval(()=>{if(!document.hidden)loadList()},30000);
})();
</script>
